try{
	//debugger;
	var sourceEvent = event.getXPath()
	if ((sourceEvent == ThisCourtToExecute.dataBinding) || (sourceEvent == REF_DATA_XPATH + "/OwningCourt/Courts[position() = 1]"))
	{
		var thisOffice = Services.getValue(ThisCourtToExecute.dataBinding);
		if (!CaseManUtils.isBlank(thisOffice))
		{
			if (thisOffice == "Y")
			{
				var node = Services.getNode(REF_DATA_XPATH + "/OwningCourt/Courts/Court");
				var name = XML.getNodeTextContent(node.selectSingleNode("Name"));
				//var addressId = XML.getNodeTextContent(node.selectSingleNode("ContactDetails/Address[1]/AddressId"));	
				//var address1 = XML.getNodeTextContent(node.selectSingleNode("ContactDetails/Address[1]/Line[1]"));	
				//var address2 = XML.getNodeTextContent(node.selectSingleNode("ContactDetails/Address[1]/Line[2]"));
				//var address3 = XML.getNodeTextContent(node.selectSingleNode("ContactDetails/Address[1]/Line[3]"));
				//var address4 = XML.getNodeTextContent(node.selectSingleNode("ContactDetails/Address[1]/Line[4]"));	
				//var postCode = XML.getNodeTextContent(node.selectSingleNode("ContactDetails/Address[1]/PostCode"));	
				//Services.setValue(HearingCourtAddressId.dataBinding, addressId);			
				Services.setValue(NameOfCourt.dataBinding, name);
				//Services.setValue(HearingVenueAddressLine1.dataBinding, address1);
				//Services.setValue(HearingVenueAddressLine2.dataBinding, address2);
				//Services.setValue(HearingVenueAddressLine3.dataBinding, address3);
				//Services.setValue(HearingVenueAddressLine4.dataBinding, address4);
				//Services.setValue(HearingVenuePostcode.dataBinding, postCode);				
			}
		}
	}
}
catch(e)
{
	// Exception may arise depending upon the event. So do nothing.
}
